import { defined } from '../utils/zcutils';

export function GeoHighlighter(chart, renderer) {
    this.chart = chart;
    this.renderer = renderer;
}

var proto = GeoHighlighter.prototype;

proto.data = function(point) {
    var chart = this.chart;
    // return function() {
    if (!chart.cache.data[point._key]) {
        chart.cache.data[point._key] = {};
    }
    var cache = chart.cache.data[point._key];
    if (!defined(cache._x)) {
        let transPoint = chart.dataObject.getXYPoint(point);
        cache._x = point._x = cache._x || transPoint.x;
        cache._y = point._y = cache._y || transPoint.y;
        if(chart.dataObject.hasZaxis){
            cache._size = point._size = cache._size || chart.dataObject.getZFromPoint(point);
        }
        point._visible = true;
        cache._point = point;
    }
    // };
    return point;
};
